class MagixTableSelection{constructor(){this.init()}init(){document.addEventListener("click",(e=>{const c=e.target.closest(".update-checkbox");if(!c)return;e.preventDefault();const t="check-all"===c.value;document.querySelectorAll("tbody .table-check").forEach((e=>{e.checked=t}));const n=document.querySelector(".check-all");n&&(n.checked=t)})),document.addEventListener("change",(e=>{if(e.target.classList.contains("check-all")){const c=e.target.checked;document.querySelectorAll("tbody .table-check").forEach((e=>{e.checked=c}))}}))}}document.addEventListener("DOMContentLoaded",(()=>new MagixTableSelection));